using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;

namespace ResearchAgent;

public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _http = new();

    [Description("Searches the web for the given query and returns a summary of results. Use this to find information about a topic.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await _http.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            return ParseSearchResults(html, query);
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html, string query)
    {
        var results = new StringBuilder();
        results.AppendLine($"Search results for: {query}");
        results.AppendLine();

        // Extract result snippets from DuckDuckGo HTML
        var snippetMarker = "result__snippet";
        var titleMarker = "result__a";
        var count = 0;

        var span = html.AsSpan();
        var pos = 0;

        while (count < 5 && pos < span.Length)
        {
            var snippetIdx = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal);
            if (snippetIdx < 0) break;

            var snippet = ExtractTagContent(html, snippetIdx);
            var titleIdx = html.LastIndexOf(titleMarker, snippetIdx, StringComparison.Ordinal);
            var title = titleIdx >= 0 ? ExtractTagContent(html, titleIdx) : "Untitled";
            var href = titleIdx >= 0 ? ExtractHref(html, titleIdx) : "";

            if (!string.IsNullOrWhiteSpace(snippet))
            {
                count++;
                results.AppendLine($"{count}. {StripHtml(title)}");
                if (!string.IsNullOrEmpty(href))
                    results.AppendLine($"   URL: {href}");
                results.AppendLine($"   {StripHtml(snippet)}");
                results.AppendLine();
            }

            pos = snippetIdx + snippetMarker.Length;
        }

        if (count == 0)
            results.AppendLine("No results found.");

        return results.ToString();
    }

    private static string ExtractTagContent(string html, int markerPos)
    {
        var closeAngle = html.IndexOf('>', markerPos);
        if (closeAngle < 0) return "";

        var openTag = html.IndexOf('<', closeAngle + 1);
        if (openTag < 0) openTag = html.Length;

        // Get text until closing tag, stripping inner HTML
        var endTag = html.IndexOf("</", closeAngle + 1, StringComparison.Ordinal);
        if (endTag < 0) endTag = openTag;

        var content = html[(closeAngle + 1)..endTag];
        return content.Trim();
    }

    private static string ExtractHref(string html, int markerPos)
    {
        var tagStart = html.LastIndexOf('<', markerPos);
        if (tagStart < 0) return "";

        var hrefIdx = html.IndexOf("href=\"", tagStart, StringComparison.OrdinalIgnoreCase);
        if (hrefIdx < 0 || hrefIdx > markerPos + 200) return "";

        var start = hrefIdx + 6;
        var end = html.IndexOf('"', start);
        if (end < 0) return "";

        var href = html[start..end];

        // DuckDuckGo wraps URLs in a redirect; extract the actual URL
        if (href.Contains("uddg=", StringComparison.Ordinal))
        {
            var uddgIdx = href.IndexOf("uddg=", StringComparison.Ordinal) + 5;
            var ampIdx = href.IndexOf('&', uddgIdx);
            var raw = ampIdx > 0 ? href[uddgIdx..ampIdx] : href[uddgIdx..];
            href = WebUtility.UrlDecode(raw);
        }

        return href;
    }

    private static string StripHtml(string html)
    {
        var result = new StringBuilder(html.Length);
        var inTag = false;
        foreach (var c in html)
        {
            if (c == '<') { inTag = true; continue; }
            if (c == '>') { inTag = false; continue; }
            if (!inTag) result.Append(c);
        }

        return WebUtility.HtmlDecode(result.ToString().Trim());
    }

    public void Dispose() => _http.Dispose();
}

using System.ComponentModel;

namespace ResearchAgent;

public sealed class Notebook
{
    private readonly List<string> _notes = [];
    private readonly Lock _lock = new();

    [Description("Saves a note with key findings from research. Use this to record important information discovered during web searches.")]
    public Task<string> SaveNoteAsync(
        [Description("The note content to save")] string content)
    {
        lock (_lock)
        {
            _notes.Add(content);
        }

        return Task.FromResult($"Note #{_notes.Count} saved.");
    }

    [Description("Reads all saved notes. Use this to review collected research before writing a summary.")]
    public Task<string> ReadNotesAsync()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
                return Task.FromResult("No notes saved yet.");

            var result = string.Join(
                Environment.NewLine,
                _notes.Select((n, i) => $"[{i + 1}] {n}"));

            return Task.FromResult(result);
        }
    }

    public IReadOnlyList<string> GetAllNotes()
    {
        lock (_lock)
        {
            return [.. _notes];
        }
    }
}

