+public sealed class Notebook
+{
+    private readonly List<string> _notes = [];
+    private readonly Lock _lock = new();
+
+    [Description("Saves a note with key findings from research. Use this to record important information discovered during web searches.")]
+    public Task<string> SaveNoteAsync(
+        [Description("The note content to save")] string content)
+    {
+        lock (_lock)
+        {
+            _notes.Add(content);
+        }
+
+        return Task.FromResult($"Note #{_notes.Count} saved.");
+    }
+
+    [Description("Reads all saved notes. Use this to review collected research before writing a summary.")]
+    public Task<string> ReadNotesAsync()
+    {
+        lock (_lock)
+        {
+            if (_notes.Count == 0)
+                return Task.FromResult("No notes saved yet.");
+
+            var result = string.Join(
+                Environment.NewLine,
+                _notes.Select((n, i) => $"[{i + 1}] {n}"));
+
+            return Task.FromResult(result);
+        }
+    }
+
+    public IReadOnlyList<string> GetAllNotes()
+    {
+        lock (_lock)
+        {
+            return [.. _notes];
+        }
+    }
+}
