services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseLogging()
    .Use(new OpenAIClient(new ApiKeyCredential(apiKey))
        .GetChatClient(modelId)
        .AsIChatClient()));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var logger = sp.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

// Tools
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNoteAsync),
    AIFunctionFactory.Create(notebook.ReadNotesAsync),
};

// Agent
var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Instructions = """
        You are a research assistant. When given a topic:
        1. Use the web search tool to find relevant information (make 2-3 searches with different queries).
        2. Save key findings as notes using the note-taking tool.
        3. Read back your notes and produce a concise summary with references.
        Be thorough but concise. Cite sources where possible.
        """,
    DefaultToolMode = ChatToolMode.Auto,
    Tools = [.. tools],
});

// Run
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

string? finalResponse = null;
await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
        finalResponse = message.Text;
    }

    logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
        message.Role, message.Text?.Length ?? 0);
}

Console.WriteLine("\n\n--- Notes collected ---");
foreach (var note in notebook.GetAllNotes())
{
    Console.WriteLine($"  • {note}");
}

